import{_ as s,c as t,o as i,ae as n}from"./chunks/framework.Cd-3tpCq.js";const a="/assets/xdebug-01.D7Ow4YAX.png",r="/assets/xdebug-02.DI0mcy_L.png",o="/assets/xdebug-03.MMme0aVD.png",v=JSON.parse('{"title":"🐛 Xdebug","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-project/installation/xdebug.md","filePath":"drupal-project/installation/xdebug.md"}'),l={name:"drupal-project/installation/xdebug.md"};function d(p,e,u,g,c,h){return i(),t("div",null,e[0]||(e[0]=[n(`<h1 id="🐛-xdebug" tabindex="-1">🐛 Xdebug <a class="header-anchor" href="#🐛-xdebug" aria-label="Permalink to &quot;🐛 Xdebug&quot;">​</a></h1><h2 id="c-est-quoi-xdebug" tabindex="-1">C&#39;est quoi Xdebug ? <a class="header-anchor" href="#c-est-quoi-xdebug" aria-label="Permalink to &quot;C&#39;est quoi Xdebug ?&quot;">​</a></h2><p><a href="https://xdebug.org/" target="_blank" rel="noreferrer">Xdebug</a> est une <strong>extension PHP</strong> qui fournit des fonctionnalités de débogage et de profilage pour vos applications PHP. C&#39;est l&#39;outil indispensable de tout développeur PHP.</p><p>Concrètement, Xdebug permet de :</p><ul><li><strong>Poser des points d&#39;arrêt</strong> (breakpoints) dans votre code pour stopper l&#39;exécution à un endroit précis.</li><li><strong>Inspecter les variables</strong> en temps réel : voir leur valeur, leur type, leur contenu.</li><li><strong>Exécuter le code pas à pas</strong> (step into, step over, step out) pour suivre le flux d&#39;exécution.</li><li><strong>Analyser la pile d&#39;appels</strong> (call stack) pour comprendre comment on est arrivé à un endroit du code.</li><li><strong>Profiler les performances</strong> pour identifier les goulots d&#39;étranglement.</li></ul><div class="tip custom-block"><p class="custom-block-title">Adieu var_dump() et dump() !</p><p>Avec Xdebug, vous n&#39;avez plus besoin de placer des <code>var_dump()</code>, <code>dump()</code> ou <code>dd()</code> partout dans votre code pour comprendre ce qu&#39;il se passe. Vous pouvez inspecter n&#39;importe quelle variable directement depuis votre IDE, à n&#39;importe quel moment de l&#39;exécution.</p></div><h2 id="ddev-et-xdebug" tabindex="-1">DDEV et Xdebug <a class="header-anchor" href="#ddev-et-xdebug" aria-label="Permalink to &quot;DDEV et Xdebug&quot;">​</a></h2><p>Bonne nouvelle : <strong>DDEV intègre Xdebug nativement</strong>. Vous n&#39;avez rien à installer ni à configurer côté serveur. <strong>Xdebug</strong> est déjà présent dans le conteneur web, prêt à être utilisé.</p><p>Par défaut, <strong>Xdebug</strong> est <strong>désactivé</strong> pour des raisons de performances. Il suffit de l&#39;activer quand vous en avez besoin.</p><p><strong>DDEV</strong> propose plusieurs commandes pour gérer <strong>Xdebug</strong> :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Activer Xdebug</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xdebug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Désactiver Xdebug</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xdebug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> off</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Vérifier l&#39;état actuel de Xdebug</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xdebug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Pensez à désactiver Xdebug quand vous ne l&#39;utilisez pas</p><p><strong>Xdebug</strong> a un impact significatif sur les performances. Votre site sera sensiblement plus lent quand <strong>Xdebug</strong> est activé. Pensez à le désactiver dès que vous avez terminé votre session de débogage.</p></div><h2 id="configuration-dans-phpstorm" tabindex="-1">Configuration dans PHPStorm <a class="header-anchor" href="#configuration-dans-phpstorm" aria-label="Permalink to &quot;Configuration dans PHPStorm&quot;">​</a></h2><p>Si vous avez installé le plugin <strong>DDEV Integration</strong>, vous n&#39;avez presque rien à faire !</p><p>Le plugin a automatiquement configuré <strong>PHPStorm</strong>. Vérifions ça ensemble.</p><p>Dans <em>Settings -&gt; PHP</em>, sélectionnez <code>cinecritique (8.4.20)</code> en tant que <code>CLI interpreter</code>.</p><p><img src="`+a+'" alt="Settings -&gt; PHP : CLI interpreter"><em>Settings PHP</em></p><p>Dans <em>Settings -&gt; PHP -&gt; Servers</em>, vérifiez que <code>cinecritique.ddev.site</code> existe.</p><p><img src="'+r+'" alt="Settings -&gt; PHP -&gt; Servers"><em>Settings PHP Servers</em></p><p>Il ne reste plus qu&#39;à activer le débogage en cliquant sur <code>Start Listening for PHP Debug Connections</code> dans la barre supérieure de <strong>PHPStorm</strong>.</p><p><img src="'+o+`" alt="Icône de debug"><em>Icône de debug</em></p><p><strong>PHPStorm</strong> est prêt à utiliser <strong>Xdebug</strong>.</p><p>Pour tester, lancez <strong>PHPStorm</strong> et ouvrez le fichier <code>index.php</code> de votre projet. Placez un point d&#39;arrêt sur la première ligne du fichier et lancez le débogage. Vous devriez voir le point d&#39;arrêt s&#39;activer lorsque vous accédez à l&#39;URL de votre site dans votre navigateur.</p><p>Pour arrêter le débogage, cliquez à nouveau sur l&#39;icône de debug et désactivez <strong>Xdebug</strong> dans <strong>DDEV</strong> :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xdebug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> off</span></span></code></pre></div><p><strong>Xdebug</strong> est également disponible lors d&#39;utilisation des lignes de commande <strong>Drush</strong>. Par défaut <strong>Drush</strong> désactive <strong>Xdebug</strong> pour des raisons de performance. Pour utiliser <strong>Xdebug</strong> avec <strong>Drush</strong>, rajoutez le flag <code>--xdebug</code> à votre commande :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Afficher les différences de configuration entre la base de données </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># et les fichiers de config en activant le debug</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drush</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cst</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --xdebug</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Toujours plus d&#39;outils de développement !</p><p>Après <strong>PHPMyAdmin</strong> et <strong>Xdebug</strong>, je vous propose d&#39;installer un trio d&#39;outil qui vont nous permettre de vérifier et améliorer la qualité de notre code : <a href="/drupal-project/installation/code_quality.html">PHPUnit, PHPStan et Code Sniffer</a></p></div>`,28)]))}const m=s(l,[["render",d]]);export{v as __pageData,m as default};
